import{bQ as t,aZ as s,aL as o,u as r,v as n,I as a,bJ as e,H as g,G as p}from"./chunks/framework.D-yUR65U.js";const l=JSON.parse('{"title":"2024-Report","description":"2024，顿悟时的感慨。","frontmatter":{"title":"2024-Report","filename":251231,"tags":["杂谈"],"date":"2025-12-31T00:00:00.000Z","description":"2024，顿悟时的感慨。","top":false,"share":true,"delete":false,"head":[["link",{"rel":"canonical","href":"https://coderama.top/posts/2025/251231"}]]},"headers":[],"relativePath":"posts/2025/251231.md","filePath":"posts/2025/251231.md","lastUpdated":1775794196000}'),d={id:"达则兼济天下-穷则独善其身",tabindex:"-1"};const f=t({name:"posts/2025/251231.md"},[["render",function(t,l,f,c,i,_){const h=s("font");return o(),r("div",null,[n("h1",d,[a(h,{color:"#66ccff"},{default:e(()=>[...l[0]||(l[0]=[g("达则兼济天下 穷则独善其身",-1)])]),_:1}),l[1]||(l[1]=g()),l[2]||(l[2]=n("a",{class:"header-anchor",href:"#达则兼济天下-穷则独善其身","aria-label":'Permalink to "<font color=#66ccff>达则兼济天下 穷则独善其身</font>"'},"​",-1))]),l[3]||(l[3]=p("<p><strong>时间</strong>总是<strong>飞逝</strong>而过的，可人不总会幡然醒悟。祂<strong>带走一切</strong>，带走你的喜怒哀乐，带走你的茫然无知，带走你的醍醐灌顶，带走你的青云之志。“要是当时……”“如果那时……”人生若可重来，我恐怕大家还会<strong>重蹈覆辙</strong>:）</p><p>总之这一年是稀里糊涂的飘飞走了，<strong>独留</strong>那楼台中的<strong>惆怅</strong>。但是好在我也对专业和未来有了更深的了解，给自己制定了更新的目标，现在我手中仅剩“努力”和“努力”这两把锟斤拷，希望在新的学期能挥舞的虎虎生风。</p><p>但是我的本性仍旧江山难移；<strong>原则</strong>性问题<strong>不可</strong>能<strong>动摇</strong>，我还是<strong>非常鄙视应试</strong>型学习，就算遇到再多挫折，我还是希望能够真正的学到真本事。<strong>大环境太乱</strong>，我只能在保足自身的情况下进行<strong>无言</strong>的<strong>反抗</strong>，在逆流中寻得定海针。</p><p>假期是个学习的好时机，也不会再有学校和老师的荆棘枷锁，所以我也正好舒展灵魂，养精蓄锐，为上半年的<strong>OVERFLOW WORKFLOW</strong>做好招架。</p>",4))])}]]);export{l as __pageData,f as default};
